package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.FieldNamingStrategy;
import com.google.gson.Gson;
import com.google.gson.JsonIOException;
import com.google.gson.ReflectionAccessFilter;
import com.google.gson.ReflectionAccessFilter.FilterResult;
import com.google.gson.internal.ConstructorConstructor;
import com.google.gson.internal.Excluder;
import com.google.gson.internal.reflect.ReflectionHelper;
import com.google.gson.reflect.TypeToken;
import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.lang.reflect.Modifier;
import java.util.Arrays;
import java.util.Collections;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

public class ReflectiveTypeAdapterFactoryGetBoundFieldsTest {

  private ReflectiveTypeAdapterFactory factory;
  private ConstructorConstructor constructorConstructor;
  private FieldNamingStrategy fieldNamingPolicy;
  private Excluder excluder;
  private JsonAdapterAnnotationTypeAdapterFactory jsonAdapterFactory;

  @BeforeEach
  public void setUp() {
    constructorConstructor = mock(ConstructorConstructor.class);
    fieldNamingPolicy = mock(FieldNamingStrategy.class);
    excluder = mock(Excluder.class);
    jsonAdapterFactory = mock(JsonAdapterAnnotationTypeAdapterFactory.class);
  }

  private ReflectiveTypeAdapterFactory createFactoryWithFilters(List<ReflectionAccessFilter> filters) throws Exception {
    ReflectiveTypeAdapterFactory f = new ReflectiveTypeAdapterFactory(
        constructorConstructor, fieldNamingPolicy, excluder, jsonAdapterFactory, filters);
    return f;
  }

  private Map<String, ReflectiveTypeAdapterFactory.BoundField> invokeGetBoundFields(
      ReflectiveTypeAdapterFactory factory, Gson context, TypeToken<?> type, Class<?> raw,
      boolean blockInaccessible, boolean isRecord) throws Exception {
    Method method = ReflectiveTypeAdapterFactory.class.getDeclaredMethod(
        "getBoundFields", Gson.class, TypeToken.class, Class.class, boolean.class, boolean.class);
    method.setAccessible(true);
    @SuppressWarnings("unchecked")
    Map<String, ReflectiveTypeAdapterFactory.BoundField> result =
        (Map<String, ReflectiveTypeAdapterFactory.BoundField>) method.invoke(factory, context, type, raw, blockInaccessible, isRecord);
    return result;
  }

  // Helper class with fields for testing
  private static class TestClass {
    public int publicField;
    private String privateField;
    static int staticField;
  }

  // Helper subclass to test multiple fields with same Json name
  private static class ConflictClass {
    @com.google.gson.annotations.SerializedName("conflict")
    public int field1;
    @com.google.gson.annotations.SerializedName("conflict")
    public int field2;
  }

  @Test
  public void testReturnsEmptyMapForInterface() throws Exception {
    ReflectiveTypeAdapterFactory factory = createFactoryWithFilters(Collections.emptyList());
    Map<String, ReflectiveTypeAdapterFactory.BoundField> result = invokeGetBoundFields(
        factory, mock(Gson.class), TypeToken.get(List.class), List.class, false, false);
    assertNotNull(result);
    assertTrue(result.isEmpty());
  }

  @Test
  public void testIncludesSerializableAndDeserializableFields() throws Exception {
    ReflectiveTypeAdapterFactory factory = spy(createFactoryWithFilters(Collections.emptyList()));
    Gson gson = mock(Gson.class);
    TypeToken<TestClass> typeToken = TypeToken.get(TestClass.class);

    // Mock includeField to allow all fields for serialization and deserialization
    doReturn(true).when(factory).includeField(any(Field.class), eq(true));
    doReturn(true).when(factory).includeField(any(Field.class), eq(false));

    // Mock getFieldNames to return default field name
    doCallRealMethod().when(factory).getFieldNames(any(Field.class));

    // Mock createBoundField to return a dummy BoundField
    doAnswer(invocation -> {
      String name = invocation.getArgument(3);
      Field field = invocation.getArgument(1);
      return new ReflectiveTypeAdapterFactory.BoundField(name, field);
    }).when(factory).createBoundField(
        any(Gson.class), any(Field.class), any(), anyString(),
        any(TypeToken.class), anyBoolean(), anyBoolean(), anyBoolean());

    Map<String, ReflectiveTypeAdapterFactory.BoundField> result = invokeGetBoundFields(
        factory, gson, typeToken, TestClass.class, false, false);

    assertNotNull(result);
    // Should contain publicField and privateField (staticField excluded by default)
    assertTrue(result.containsKey("publicField"));
    assertTrue(result.containsKey("privateField"));
    assertFalse(result.containsKey("staticField"));
  }

  @Test
  public void testThrowsJsonIOExceptionWhenFilterBlocksAllOnSupertype() throws Exception {
    ReflectionAccessFilter filter = mock(ReflectionAccessFilter.class);
    when(filter.filterType(any(Class.class))).thenReturn(FilterResult.BLOCK_ALL);

    ReflectiveTypeAdapterFactory factory = createFactoryWithFilters(Collections.singletonList(filter));
    Gson gson = mock(Gson.class);

    // Use a subclass to ensure superclass filtering triggers
    class SuperClassWithField {
      public int field;
    }
    class SubClass extends SuperClassWithField {}

    TypeToken<SubClass> typeToken = TypeToken.get(SubClass.class);

    JsonIOException thrown = assertThrows(JsonIOException.class, () -> {
      invokeGetBoundFields(factory, gson, typeToken, SubClass.class, false, false);
    });
    assertTrue(thrown.getMessage().contains("ReflectionAccessFilter does not permit using reflection"));
  }

  @Test
  public void testBlockInaccessibleFlagChangesBehavior() throws Exception {
    ReflectionAccessFilter filter = mock(ReflectionAccessFilter.class);
    when(filter.filterType(any(Class.class))).thenReturn(FilterResult.BLOCK_INACCESSIBLE);

    ReflectiveTypeAdapterFactory factory = spy(createFactoryWithFilters(Collections.singletonList(filter)));
    Gson gson = mock(Gson.class);
    TypeToken<TestClass> typeToken = TypeToken.get(TestClass.class);

    doReturn(true).when(factory).includeField(any(Field.class), eq(true));
    doReturn(true).when(factory).includeField(any(Field.class), eq(false));
    doCallRealMethod().when(factory).getFieldNames(any(Field.class));
    doAnswer(invocation -> {
      String name = invocation.getArgument(3);
      Field field = invocation.getArgument(1);
      return new ReflectiveTypeAdapterFactory.BoundField(name, field);
    }).when(factory).createBoundField(
        any(Gson.class), any(Field.class), any(), anyString(),
        any(TypeToken.class), anyBoolean(), anyBoolean(), anyBoolean());

    Map<String, ReflectiveTypeAdapterFactory.BoundField> result = invokeGetBoundFields(
        factory, gson, typeToken, TestClass.class, false, false);

    assertNotNull(result);
    assertTrue(result.containsKey("publicField"));
    assertTrue(result.containsKey("privateField"));
  }

  @Test
  public void testIsRecordTrueUsesAccessorMethod() throws Exception {
    ReflectiveTypeAdapterFactory factory = spy(createFactoryWithFilters(Collections.emptyList()));
    Gson gson = mock(Gson.class);

    // Create a record with one field
    record RecordClass(int x) {}

    TypeToken<RecordClass> typeToken = TypeToken.get(RecordClass.class);

    doReturn(true).when(factory).includeField(any(Field.class), eq(true));
    doReturn(true).when(factory).includeField(any(Field.class), eq(false));
    doCallRealMethod().when(factory).getFieldNames(any(Field.class));

    try (MockedStatic<ReflectionHelper> mockedReflectionHelper = Mockito.mockStatic(ReflectionHelper.class)) {
      mockedReflectionHelper.when(() -> ReflectionHelper.getAccessor(any(), any())).thenAnswer(invocation -> {
        Method m = RecordClass.class.getDeclaredMethod("x");
        return m;
      });
      mockedReflectionHelper.when(() -> ReflectionHelper.makeAccessible(any(Method.class))).then(invocation -> null);

      doAnswer(invocation -> {
        String name = invocation.getArgument(3);
        Field field = invocation.getArgument(1);
        return new ReflectiveTypeAdapterFactory.BoundField(name, field);
      }).when(factory).createBoundField(
          any(Gson.class), any(Field.class), any(Method.class), anyString(),
          any(TypeToken.class), anyBoolean(), anyBoolean(), anyBoolean());

      Map<String, ReflectiveTypeAdapterFactory.BoundField> result = invokeGetBoundFields(
          factory, gson, typeToken, RecordClass.class, false, true);

      assertNotNull(result);
      assertTrue(result.containsKey("x"));
    }
  }

  @Test
  public void testThrowsJsonIOExceptionWhenSerializedNameOnAccessor() throws Exception {
    ReflectiveTypeAdapterFactory factory = spy(createFactoryWithFilters(Collections.emptyList()));
    Gson gson = mock(Gson.class);

    class RecordWithSerializedName {
      private int value;
      public RecordWithSerializedName(int value) { this.value = value; }
      @com.google.gson.annotations.SerializedName("valueAlias")
      public int value() { return value; }
    }

    TypeToken<RecordWithSerializedName> typeToken = TypeToken.get(RecordWithSerializedName.class);

    doReturn(true).when(factory).includeField(any(Field.class), eq(true));
    doReturn(true).when(factory).includeField(any(Field.class), eq(false));
    doCallRealMethod().when(factory).getFieldNames(any(Field.class));

    try (MockedStatic<ReflectionHelper> mockedReflectionHelper = Mockito.mockStatic(ReflectionHelper.class)) {
      Method accessor = RecordWithSerializedName.class.getDeclaredMethod("value");
      mockedReflectionHelper.when(() -> ReflectionHelper.getAccessor(any(), any())).thenReturn(accessor);
      mockedReflectionHelper.when(() -> ReflectionHelper.makeAccessible(any(Method.class))).then(invocation -> null);
      mockedReflectionHelper.when(() -> ReflectionHelper.getAccessibleObjectDescription(accessor, false)).thenReturn("method value()");

      JsonIOException thrown = assertThrows(JsonIOException.class, () -> {
        invokeGetBoundFields(factory, gson, typeToken, RecordWithSerializedName.class, false, true);
      });
      assertTrue(thrown.getMessage().contains("@SerializedName on method value() is not supported"));
    }
  }

  @Test
  public void testThrowsIllegalArgumentExceptionOnFieldNameConflict() throws Exception {
    ReflectiveTypeAdapterFactory factory = spy(createFactoryWithFilters(Collections.emptyList()));
    Gson gson = mock(Gson.class);
    TypeToken<ConflictClass> typeToken = TypeToken.get(ConflictClass.class);

    doReturn(true).when(factory).includeField(any(Field.class), eq(true));
    doReturn(true).when(factory).includeField(any(Field.class), eq(false));
    doCallRealMethod().when(factory).getFieldNames(any(Field.class));

    try (MockedStatic<ReflectionHelper> mockedReflectionHelper = Mockito.mockStatic(ReflectionHelper.class)) {
      mockedReflectionHelper.when(() -> ReflectionHelper.fieldToString(any(Field.class))).thenAnswer(invocation -> {
        Field f = invocation.getArgument(0);
        return f.getName();
      });

      doAnswer(invocation -> {
        String name = invocation.getArgument(3);
        Field field = invocation.getArgument(1);
        return new ReflectiveTypeAdapterFactory.BoundField(name, field);
      }).when(factory).createBoundField(
          any(Gson.class), any(Field.class), any(), anyString(),
          any(TypeToken.class), anyBoolean(), anyBoolean(), anyBoolean());

      IllegalArgumentException thrown = assertThrows(IllegalArgumentException.class, () -> {
        invokeGetBoundFields(factory, gson, typeToken, ConflictClass.class, false, false);
      });
      assertTrue(thrown.getMessage().contains("declares multiple JSON fields named 'conflict'"));
    }
  }
}
